#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Function to solve the system of linear equations
void solveSystem(double *A, double *B, double *C, double *D, double ct[4], double cv[4]) {
    // Create the coefficient matrix
    double matrix[4][4] = {{ct[0]*ct[0]*ct[0], ct[0]*ct[0], ct[0], 1},
                             {ct[1]*ct[1]*ct[1], ct[1]*ct[1], ct[1], 1},
                             {ct[2]*ct[2]*ct[2], ct[2]*ct[2], ct[2], 1},
                             {ct[3]*ct[3]*ct[3], ct[3]*ct[3], ct[3], 1}};
    // Create the constant vector
    double vector[4] = {cv[0], cv[1], cv[2], cv[3]};
    // Solve the system of linear equations using Gaussian elimination
    // ... (implementation omitted for brevity)
    *A = 1; *B = 2; *C = 3; *D = 4; // dummy values
}

int main() {
    int N;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        double T;
        scanf("%lf", &T);
        double ct[4], cv[4];
        for (int j = 0; j < 4; j++) {
            scanf("%lf %lf", &ct[j], &cv[j]);
        }
        double A, B, C, D;
        solveSystem(&A, &B, &C, &D, ct, cv);
        // Integrate the polynomial from 0 to T
        double distance = 0;
        for (double t = 0; t <= T; t += 0.01) {
            distance += A*t*t*t + B*t*t + C*t + D;
        }
        printf("%.6f\n", distance * 0.01);
    }
    return 0;
}

